noncompliant:
class MyClass {
private:
  int value = 42;
public:
  auto getBadLambda() {
    return [value]() { // Noncompliant - captures 'this' implicitly
      return value; // Actually accessing this->value
    };
  }
};

class Example {
  std::string name;
public:
  void setupCallback() {
    auto callback = [name]() { // Noncompliant - misleading capture
      std::cout << name; // Actually this->name
    };
  }
};

compliant:
class MyClass {
private:
  int value = 42;
public:
  auto getGoodLambda() {
    return [this]() { // Compliant - explicit this capture
      return value;
    };
  }
};

class Example {
  std::string name;
public:
  void setupCallback() {
    auto callback = [this]() { // Compliant - explicit capture
      std::cout << name;
    };
    // Or capture by value if safe
    auto safeCopy = name;
    auto safeCallback = [safeCopy]() { // Compliant
      std::cout << safeCopy;
    };
  }
};
